document.addEventListener("DOMContentLoaded", () => {
  // ==========================================
  // 1. CUSTOM CURSOR
  // ==========================================
  const cursor = document.getElementById("cursor");
  const cursorRing = document.getElementById("cursor-ring");
  let mx = 0,
    my = 0,
    rx = 0,
    ry = 0;

  // Hapus pengecekan isTouchDevice yang kaku agar laptop touchscreen tetap memunculkan kursor
  if (cursor && cursorRing) {
    document.addEventListener("mousemove", (e) => {
      mx = e.clientX;
      my = e.clientY;
      cursor.style.left = mx + "px";
      cursor.style.top = my + "px";
    });

    function animateRing() {
      rx += (mx - rx) * 0.12;
      ry += (my - ry) * 0.12;
      cursorRing.style.left = rx + "px";
      cursorRing.style.top = ry + "px";
      requestAnimationFrame(animateRing);
    }
    animateRing();

    // Hover Effect
    document
      .querySelectorAll(
        "a, button, .skill-card, .org-card, .contact-link, .download-cv-btn",
      )
      .forEach((el) => {
        el.addEventListener("mouseenter", () =>
          document.body.classList.add("cursor-hover"),
        );
        el.addEventListener("mouseleave", () =>
          document.body.classList.remove("cursor-hover"),
        );
      });
  }

  // ==========================================
  // 2. PRELOADER TERMINAL ENGINE
  // ==========================================
  const preLines = [
    { text: "> initializing system...", cls: "" },
    { text: "> loading profile: danish.athayan", cls: "green" },
    { text: "> decrypting cv_data.json", cls: "" },
    { text: "> skill_scan: penetration_testing ✓", cls: "green" },
    { text: "> skill_scan: network_security ✓", cls: "green" },
    { text: "> skill_scan: osint_framework ✓", cls: "green" },
    { text: "> connecting to portfolio server...", cls: "" },
    { text: "> HANDSHAKE COMPLETE. WELCOME.", cls: "amber" },
  ];

  let pli = 0;
  const linesEl = document.getElementById("preLines");
  const barEl = document.getElementById("preBar");
  const pctEl = document.getElementById("prePct");
  const preloaderEl = document.getElementById("preloader");

  function nextLine() {
    if (!linesEl || !barEl || !pctEl) {
      startTerminal();
      return;
    }

    if (pli >= preLines.length) {
      barEl.style.width = "100%";
      pctEl.textContent = "100%";
      setTimeout(() => {
        if (preloaderEl) {
          preloaderEl.classList.add("done");
          setTimeout(() => {
            preloaderEl.style.display = "none";
            startTerminal();
          }, 600);
        } else {
          startTerminal();
        }
      }, 400);
      return;
    }

    const l = preLines[pli];
    const div = document.createElement("div");
    div.className = "pre-line" + (l.cls ? " " + l.cls : "");
    div.textContent = l.text;
    div.style.animationDelay = "0s";
    linesEl.appendChild(div);
    pli++;

    const pct = Math.round((pli / preLines.length) * 95);
    barEl.style.width = pct + "%";
    pctEl.textContent = pct + "%";
    setTimeout(nextLine, 180 + Math.random() * 100);
  }

  if (preloaderEl) {
    setTimeout(nextLine, 300);
  } else {
    startTerminal();
  }

  // ==========================================
  // 3. TERMINAL ANIMATION
  // ==========================================
  function startTerminal() {
    const terminalItems = [
      "t1",
      "t2",
      "t3",
      "t4",
      "t5",
      "t6",
      "t7",
      "t8",
      "t9",
      "t10",
      "t11",
      "t12",
    ];
    terminalItems.forEach((id, i) => {
      setTimeout(() => {
        const el = document.getElementById(id);
        if (el) el.style.opacity = "1";
      }, i * 220);
    });
  }

  // ==========================================
  // 4. THEME TOGGLE
  // ==========================================
  let isDark = true;
  const themeToggleBtn = document.getElementById("themeToggle");

  if (themeToggleBtn) {
    themeToggleBtn.addEventListener("click", () => {
      isDark = !isDark;
      document.documentElement.setAttribute(
        "data-theme",
        isDark ? "dark" : "light",
      );
      themeToggleBtn.textContent = isDark ? "[ LIGHT ]" : "[ DARK ]";
    });
  }

  // ==========================================
  // 5. NAVIGATION (BURGER MENU)
  // ==========================================
  const burger = document.getElementById("burger");
  const mobileMenu = document.getElementById("mobileMenu");

  if (burger && mobileMenu) {
    burger.addEventListener("click", () => {
      burger.classList.toggle("open");
      mobileMenu.classList.toggle("open");
    });

    // Menutup menu saat link navigasi diklik
    mobileMenu.querySelectorAll("a").forEach((link) => {
      link.addEventListener("click", closeMobile);
    });
  }

  function closeMobile() {
    if (burger) burger.classList.remove("open");
    if (mobileMenu) mobileMenu.classList.remove("open");
  }

  // ==========================================
  // 6. SCROLL REVEAL ENGINE
  // ==========================================
  const reveals = document.querySelectorAll(".reveal");
  if (reveals.length > 0) {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((e, i) => {
          if (e.isIntersecting) {
            setTimeout(() => e.target.classList.add("visible"), i * 60);
          }
        });
      },
      { threshold: 0.1, rootMargin: "0px 0px -40px 0px" },
    );

    reveals.forEach((el) => observer.observe(el));
  }

  // ==========================================
  // 7. MARQUEE TRACK GENERATOR
  // ==========================================
  const marqueeItems = [
    "PENETRATION TESTING",
    "ETHICAL HACKING",
    "NETWORK SECURITY",
    "OSINT",
    "CTF CHAMPION",
    "WEB3 / DEFI",
    "KALI LINUX",
    "BURP SUITE",
    "NEXT.JS",
    "BLOCKCHAIN",
    "SOUND TECHNICIAN",
    "VIDEO MAPPING",
  ];
  const track = document.getElementById("marqueeTrack");

  if (track) {
    const doubled = [
      ...marqueeItems,
      ...marqueeItems,
      ...marqueeItems,
      ...marqueeItems,
    ];
    doubled.forEach((item) => {
      const span = document.createElement("span");
      span.className = "marquee-item";
      span.innerHTML = `${item}<span class="sep">◆</span>`;
      track.appendChild(span);
    });
  }

  // ==========================================
  // 8. TEXT SCRAMBLE (GLITCH EFFECT)
  // ==========================================
  function scramble(el, final, duration = 800) {
    const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*";
    let frame = 0;
    const total = Math.floor(duration / 30);
    const interval = setInterval(() => {
      el.textContent = final
        .split("")
        .map((c, i) => {
          if (frame / total > i / final.length) return c;
          return chars[Math.floor(Math.random() * chars.length)];
        })
        .join("");
      frame++;
      if (frame >= total) {
        el.textContent = final;
        clearInterval(interval);
      }
    }, 30);
  }

  document.querySelectorAll(".glitch").forEach((el) => {
    el.addEventListener("mouseenter", () => {
      const textAttr = el.getAttribute("data-text");
      if (textAttr) scramble(el, textAttr);
    });
  });

  // ==========================================
// 9. NETLIFY SERVERLESS CONFIG
// ==========================================
// API Key sekarang aman disimpan di dashboard Netlify, bukan di sini lagi!
const NETLIFY_FUNCTION_URL = "/.netlify/functions/send-email";

// ==========================================
// 10. CONTACT FORM HANDLER (NETLIFY + RESEND)
// ==========================================
function handleSubmit(e) {
  e.preventDefault();
  const btn = document.getElementById("submitBtn");
  const form = e.target;

  const nameEl = form.querySelector('input[type="text"]');
  const emailEl = form.querySelector('input[type="email"]');
  const msgEl = form.querySelector("textarea");

  if (!btn || !nameEl || !emailEl || !msgEl) return;

  btn.textContent = "> TRANSMITTING...";
  btn.disabled = true;

  // Mengirim data ke Netlify Serverless Function kamu
  fetch(NETLIFY_FUNCTION_URL, {
    method: "POST",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      name: nameEl.value,
      email: emailEl.value,
      message: msgEl.value,
    })
  })
  .then((response) => {
    if (!response.ok) {
      throw new Error("Serverless Function error");
    }
    return response.json();
  })
  .then(() => {
    btn.textContent = "> MESSAGE_SENT ✓";
    btn.style.background = "var(--green)"; // Diubah ke green agar estetik tanda sukses
    form.reset();
    setTimeout(() => {
      btn.textContent = "→ SEND_MESSAGE";
      btn.disabled = false;
      btn.style.background = "";
    }, 3000);
  })
  .catch((err) => {
    console.error("Netlify Function error:", err);
    btn.textContent = "> ERROR — TRY AGAIN";
    btn.style.background = "var(--red)";
    btn.disabled = false;
    setTimeout(() => {
      btn.textContent = "→ SEND_MESSAGE";
      btn.style.background = "";
    }, 3000);
  });
}

// Daftarkan Event Listener di paling akhir agar fungsi handleSubmit sudah siap dieksekusi
const contactForm = document.querySelector(".contact-form");
if (contactForm) {
  contactForm.addEventListener("submit", handleSubmit);
}

  // PDF Download (base64 embedded)
  const CV_BASE64 =
    "";
  // TRIGGER DOWNLOAD LOGIC
  function triggerCVDownload() {
    try {
      // Konversi Base64 string ke data biner
      const byteCharacters = atob(CV_BASE64);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: "application/pdf" });

      // Membuat link unduhan virtual di memori browser
      const blobURL = window.URL.createObjectURL(blob);
      const downloadLink = document.createElement("a");
      downloadLink.href = blobURL;
      downloadLink.download = "CV_Danish_Athaya_Natasurendra.pdf";

      // Eksekusi proses download secara tersembunyi
      document.body.appendChild(downloadLink);
      downloadLink.click();

      // Cleanup memory setelah download berhasil dieksekusi
      document.body.removeChild(downloadLink);
      window.URL.revokeObjectURL(blobURL);
    } catch (error) {
      console.error("Kritis: Engine gagal memproses payload CV_BASE64:", error);
    }
  }

  // Sambungkan fungsi ke seluruh elemen tombol download CV di website Anda
  // Gunakan class atau ID ini pada tag HTML tombol download Anda (contoh: <button id="downloadCvBtn">)
  const downloadButton =
    document.getElementById("downloadCvBtn") ||
    document.querySelector(".download-cv-btn");
  if (downloadButton) {
    downloadButton.addEventListener("click", (e) => {
      e.preventDefault();
      triggerCVDownload();
    });
  }
});
